const stats = $node['Fetch Dashboard Stats'].json || {};
const incidentData = $node['Fetch Open Incidents'].json || {};
const incidents = Array.isArray(incidentData) ? incidentData : (incidentData.incidents || []);
const critical = incidents.filter(function(i){ return i.severity === 'CRITICAL'; }).length;
const high = incidents.filter(function(i){ return i.severity === 'HIGH'; }).length;
const medium = incidents.filter(function(i){ return i.severity === 'MEDIUM'; }).length;
const low = incidents.filter(function(i){ return i.severity === 'LOW'; }).length;
const blocked = incidents.filter(function(i){ return i.block_recommended; }).length;
const topThreats = {};
for (var inc of incidents) { var t = inc.threat_type || inc.type || 'UNKNOWN'; topThreats[t] = (topThreats[t] || 0) + 1; }
const topThreatsStr = Object.entries(topThreats).sort(function(a,b){ return b[1]-a[1]; }).slice(0,5).map(function(e){ return e[0]+': '+e[1]; }).join(', ');
const summary = { total_alerts: stats.total_alerts_24h || 0, total_incidents: stats.active_incidents || incidents.length, resolved_this_week: stats.resolved_this_week || 0, blocked_ips: stats.blocked_ips || blocked, open_critical: critical, open_high: high, open_medium: medium, open_low: low, top_threats: topThreatsStr || 'None', avg_response_time: stats.avg_response_time_min || 'N/A', week_start: new Date(Date.now()-7*24*3600*1000).toISOString().slice(0,10), week_end: new Date().toISOString().slice(0,10) };
return [{ json: summary }];

const report = ($json.choices && $json.choices[0]) ? $json.choices[0].message.content : 'Report generation failed — check OpenAI API key';
const metrics = $('Build Board Prompt').item.json.metrics;
const blocks = [{ type: 'header', text: { type: 'plain_text', text: '📊 Weekly Security Board Report', emoji: true } }, { type: 'section', text: { type: 'mrkdwn', text: '*Period:* ' + metrics.week_start + ' → ' + metrics.week_end } }, { type: 'divider' }, { type: 'section', fields: [{ type: 'mrkdwn', text: '*CRITICAL Open:* ' + metrics.open_critical }, { type: 'mrkdwn', text: '*HIGH Open:* ' + metrics.open_high }, { type: 'mrkdwn', text: '*IPs Blocked:* ' + metrics.blocked_ips }, { type: 'mrkdwn', text: '*Resolved:* ' + metrics.resolved_this_week }, { type: 'mrkdwn', text: '*Total Alerts:* ' + metrics.total_alerts }, { type: 'mrkdwn', text: '*Avg Response:* ' + metrics.avg_response_time + ' min' }] }, { type: 'divider' }, { type: 'section', text: { type: 'mrkdwn', text: report.length > 2900 ? report.slice(0,2900) + '...' : report } }, { type: 'divider' }, { type: 'context', elements: [{ type: 'mrkdwn', text: 'CyberSentinel AI · Weekly Board Report · Every Monday 8AM' }] }];
return [{ json: { channel: 'C0ANVSMJTH9', text: 'Weekly Security Report: ' + metrics.week_start + ' to ' + metrics.week_end, blocks: blocks } }];

const d = $input.first().json;
const reportId = 'board-' + new Date().toISOString().slice(0,10) + '-' + Date.now().toString(36);
return [{ json: { report_id: reportId, workflow: 'board_report', title: 'Weekly Board Report — ' + new Date().toISOString().slice(0,10), slack_payload: d } }];
